                .build();
    }

    private List<String> orderedKeys(Set<String> primary, Set<String> secondary) {
        LinkedHashSet<String> keys = new LinkedHashSet<>(primary);
        keys.addAll(secondary);
        return new ArrayList<>(keys);
    }
}

