file.content:
package com.pvreview.config;

import com.fasterxml.jackson.databind.ObjectMapper;
import io.swagger.v3.core.converter.ModelConverter;
import io.swagger.v3.core.jackson.ModelResolver;
import io.swagger.v3.oas.models.OpenAPI;
import io.swagger.v3.oas.models.info.Info;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;

@Configuration
public class OpenApiConfig {

    @Bean
    public OpenAPI pvReviewOpenApi() {
        return new OpenAPI()
                .info(new Info()
                        .title("PV Case Review API")
                        .description("Pharmacovigilance case review service: merges follow-up reports "
                                + "into stored cases and tracks reviewer queries against individual fields.")
                        .version("v0.0.1"));
    }

    // Without this, swagger-core resolves schema property names from raw Java field
    // names (camelCase) instead of the app's actual snake_case wire format, since it
    // otherwise builds its own ObjectMapper instead of using the Spring-configured one.
    @Bean
    public ModelConverter modelResolver(ObjectMapper objectMapper) {
        return new ModelResolver(objectMapper);
    }
}

plugins {
    id 'java'
    id 'org.springframework.boot' version '3.3.4'
    id 'io.spring.dependency-management' version '1.1.6'
}

group = 'com.pvreview'
version = '0.0.1-SNAPSHOT'

java {
    toolchain {
        languageVersion = JavaLanguageVersion.of(17)
    }
}

repositories {
    mavenCentral()
}

dependencies {
    implementation 'org.springframework.boot:spring-boot-starter-web'
    implementation 'org.springframework.boot:spring-boot-starter-validation'
    implementation 'org.springdoc:springdoc-openapi-starter-webmvc-ui:2.6.0'

    compileOnly 'org.projectlombok:lombok:1.18.34'
    annotationProcessor 'org.projectlombok:lombok:1.18.34'

    testCompileOnly 'org.projectlombok:lombok:1.18.34'
    testAnnotationProcessor 'org.projectlombok:lombok:1.18.34'

    testImplementation 'org.springframework.boot:spring-boot-starter-test'
}

tasks.named('test') {
    useJUnitPlatform()
}

.PHONY: help build start stop test logs clean backup restore

help:
	@echo "Usage: make <target>"
	@echo ""
	@echo "Targets:"
	@echo "  build                          Build the backend Docker image"
	@echo "  start                          Start the backend (docker compose up -d)"
	@echo "  stop                           Stop the backend (docker compose down)"
	@echo "  test                           Run the backend test suite (./gradlew test)"
	@echo "  logs                           Follow the backend container logs"
	@echo "  clean                          Stop containers, remove built images, and clean Gradle build output"
	@echo "  backup                         Snapshot all cases to backups/cases-<timestamp>.json"
	@echo "  restore FILE=...               Restore cases from a backup file (PUT, bypasses merge)"
	@echo "  restore FILE=... DRY_RUN=1     Show what restore would do without making changes"

build:
	./ops/run.sh build

start:
	./ops/run.sh start

stop:
	./ops/run.sh stop

test:
	./ops/run.sh test

logs:
	./ops/run.sh logs

clean:
	./ops/run.sh clean

backup:
	./ops/backup.sh

restore:
	./ops/restore.sh $(if $(DRY_RUN),--dry-run) $(FILE)

